MITIGATION (suggerita):
Opzione A (semplice) – passare l'override id come parametro esplicito a save:
```js
const save = async (overrideOverwriteId=null) => {
    const effectiveOw = overrideOverwriteId || form._overwrite_id;
    if (!effectiveOw) {
        const dup = await checkDup({...});
        if (dup?.existing) { setDuplicate({...}); return; }
    }
    // ... usa effectiveOw invece di form._overwrite_id
    if (effectiveOw) payload.overwrite_id = effectiveOw;
    // ... POST
};
const onConfirmOverwrite = () => {
    if (!duplicate?.existing) return;
    const ovId = duplicate.existing.id;
    setForm(f => ({ ...f, _overwrite_id: ovId }));
    setDuplicate(null);
    save(ovId);  // passa esplicitamente, no setTimeout, no stale closure
};
```

Opzione B (useEffect trigger):
```js
const [pendingOverwrite, setPendingOverwrite] = useState(null);
useEffect(() => {
    if (pendingOverwrite && form._overwrite_id === pendingOverwrite) {
        setPendingOverwrite(null);
        save();
    }
}, [form._overwrite_id, pendingOverwrite]);
const onConfirmOverwrite = () => {
    if (!duplicate?.existing) return;
    const ovId = duplicate.existing.id;
    setForm(f => ({ ...f, _overwrite_id: ovId }));
    setDuplicate(null);
    setPendingOverwrite(ovId);
};
```
